//! Auto-generated by the spec-word-compliance workflow.
//!
//! Area: "Complex field structure (fldChar/instrText nesting, begin/separate/end,
//! unclosed fields)".
//!
//! Each `#[test]` encodes a Word-consumption / serializer-emits constraint mined
//! from ISO/IEC 29500-1 §17.16 and MS-OI29500 §2.1.454. A FAILING assertion
//! means stemma diverges from Word — that is a real Word-compliance gap, NOT
//! something to make pass by weakening the test.
//!
//! Methodology (consumption vs. save):
//!   - `xml*` expectations run on the re-serialized document.xml. stemma round-
//!     trips untouched content byte-verbatim, so these are valid only for
//!     element ORDERING, structural SYNTHESIS, and validity — never for "Word
//!     normalizes value V on layout".
//!   - `acceptTextEquals` / `rejectTextEquals` run on the READ side
//!     (`read_accepted()` / `read_rejected()` -> `to_text()`), the correct
//!     surface for Word CONSUMPTION semantics.
//!   - `opensClean` asserts `stemma::api::validate(&bytes)` reports no errors.

use std::io::Read;

use stemma::api::Document;

// ─── Prelude ────────────────────────────────────────────────────────────────

/// Build a valid minimal `.docx`. `body_xml` is wrapped in
/// `<w:document …><w:body>…</w:body></w:document>`. `extra_parts` are additional
/// `word/<name>` parts (e.g. `("styles.xml", "<w:styles…>")`); each gets a
/// Content-Types override and is written into the package.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#
    );

    // Content-Types: defaults + document override + an override per extra part.
    let mut overrides = String::from(
        r#"<Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>"#,
    );
    for (name, _) in extra_parts {
        let content_type = match *name {
            "styles.xml" => {
                "application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"
            }
            "numbering.xml" => {
                "application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml"
            }
            other => panic!("make_docx: unknown extra part {other} (no Content-Type mapping)"),
        };
        overrides.push_str(&format!(
            r#"<Override PartName="/word/{name}" ContentType="{content_type}"/>"#
        ));
    }
    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/>{overrides}</Types>"#
    );

    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;

    // document.xml.rels references each extra part by a synthetic rel.
    let mut doc_rel_entries = String::new();
    for (i, (name, _)) in extra_parts.iter().enumerate() {
        let rel_type = match *name {
            "styles.xml" => {
                "http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles"
            }
            "numbering.xml" => {
                "http://schemas.openxmlformats.org/officeDocument/2006/relationships/numbering"
            }
            other => panic!("make_docx: unknown extra part {other} (no rel type)"),
        };
        doc_rel_entries.push_str(&format!(
            r#"<Relationship Id="rIdX{i}" Type="{rel_type}" Target="{name}"/>"#
        ));
    }
    let doc_rels = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">{doc_rel_entries}</Relationships>"#
    );

    use std::io::Write;
    use zip::write::FileOptions;
    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (name, content) in extra_parts {
            zip.start_file(format!("word/{name}"), opts).unwrap();
            zip.write_all(content.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip a `.docx` and return `word/document.xml` as a String.
fn document_xml_of(docx: &[u8]) -> String {
    let mut archive =
        zip::ZipArchive::new(std::io::Cursor::new(docx)).expect("open docx zip archive");
    let mut file = archive
        .by_name("word/document.xml")
        .expect("word/document.xml present in package");
    let mut s = String::new();
    file.read_to_string(&mut s).expect("read document.xml");
    s
}

/// Parse, serialize with default options, return the re-serialized document.xml.
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse for reserialize");
    let out = doc
        .serialize(&stemma::ExportOptions::default())
        .expect("serialize");
    document_xml_of(&out)
}

/// True iff `needles` appear in `haystack` in the given order (each match
/// starts at or after the end of the previous match). Used to translate the
/// spec's `xmlRegex` ordered-anchor expectations (no `regex` dev-dep available).
fn contains_in_order(haystack: &str, needles: &[&str]) -> bool {
    let mut from = 0usize;
    for needle in needles {
        match haystack[from..].find(needle) {
            Some(rel) => from = from + rel + needle.len(),
            None => return false,
        }
    }
    true
}

fn accept_text(bytes: &[u8]) -> String {
    Document::parse(bytes)
        .expect("parse for accept")
        .read_accepted()
        .expect("read_accepted")
        .to_text()
        .trim()
        .to_string()
}

fn reject_text(bytes: &[u8]) -> String {
    Document::parse(bytes)
        .expect("parse for reject")
        .read_rejected()
        .expect("read_rejected")
        .to_text()
        .trim()
        .to_string()
}

fn opens_clean(bytes: &[u8]) -> stemma::ValidationReport {
    stemma::api::validate(bytes)
}

