#[test]
fn complex_field_codes_resume_after_inner_field_end() {
    let body = r#"<w:p><w:r><w:fldChar w:fldCharType="begin"/></w:r><w:r><w:instrText xml:space="preserve">IF </w:instrText></w:r><w:r><w:fldChar w:fldCharType="begin"/></w:r><w:r><w:instrText xml:space="preserve"> DATE </w:instrText></w:r><w:r><w:fldChar w:fldCharType="separate"/></w:r><w:r><w:instrText>1-4</w:instrText></w:r><w:r><w:fldChar w:fldCharType="end"/></w:r><w:r><w:instrText>&lt;&gt;"1-1" "not "</w:instrText></w:r><w:r><w:fldChar w:fldCharType="separate"/></w:r><w:r><w:t xml:space="preserve">not </w:t></w:r><w:r><w:fldChar w:fldCharType="end"/></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let report = opens_clean(&b);
    assert!(
        report.ok,
        "ISO 29500-1 §17.16.2 / §17.16.18 — a correctly nested complex field with outer \
         codes resuming after the inner end is conformant; Word opens it without repair. \
         issues: {:?}",
        report.issues
    );

    let xml = reserialize(&b);
    // The outer instrText fragment must remain AFTER the inner end and BEFORE the
    // outer separate, then outer end last. instrText escapes &<> => &amp;&lt;&gt;.
    assert!(
        contains_in_order(
            &xml,
            &[
                "fldCharType=\"end\"",
                "&lt;&gt;\"1-1\" \"not \"",
                "fldCharType=\"separate\"",
                "fldCharType=\"end\"",
            ],
        ),
        "ISO 29500-1 §17.16.2 — outer instrText fragment must stay AFTER the inner end \
         fldChar and BEFORE the outer separate, then outer end last; reordering/dropping \
         breaks nesting. xml=\n{xml}"
    );
    assert!(
        contains_in_order(
            &xml,
            &[
                "fldCharType=\"begin\"",
                "fldCharType=\"begin\"",
                "fldCharType=\"separate\"",
                "fldCharType=\"end\"",
                "fldCharType=\"separate\"",
                "fldCharType=\"end\"",
            ],
        ),
        "ISO 29500-1 §17.16.2 — canonical nested ordering: two begins precede the inner \
         separate/end, the outer separate/end follow the inner end. xml=\n{xml}"
    );
}

#[test]
fn tracked_field_codes_mixed_ins_del_invisible_in_both_projections() {
    let body = r#"<w:p><w:r><w:fldChar w:fldCharType="begin"/></w:r><w:ins w:id="1" w:author="A" w:date="2026-01-01T00:00:00Z"><w:r><w:instrText>FORMCHECKBOX</w:instrText></w:r></w:ins><w:del w:id="2" w:author="A" w:date="2026-01-01T00:00:00Z"><w:r><w:delInstrText>FORMFIELDTEXT</w:delInstrText></w:r></w:del><w:r><w:fldChar w:fldCharType="separate"/></w:r><w:r><w:t>Yes</w:t></w:r><w:r><w:fldChar w:fldCharType="end"/></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_eq!(
        accept_text(&b),
        "Yes",
        "ISO 29500-1 §17.16.18 — field-code run content shall not be displayed; accepting \
         keeps the inserted FORMCHECKBOX code (still a non-displayed code) and drops the \
         deleted code, so only the result region 'Yes' reads."
    );
    assert_eq!(
        reject_text(&b),
        "Yes",
        "ISO 29500-1 §17.16.18 / §17.16.13 — rejecting restores FORMFIELDTEXT and drops \
         FORMCHECKBOX, but both are non-displayed field codes; the result 'Yes' is \
         untouched, so reject reads identically to accept."
    );
    let report = opens_clean(&b);
    assert!(
        report.ok,
        "ISO 29500-1 §17.16.13 — delInstrText inside w:del and instrText inside w:ins within \
         a balanced begin/separate/end field is conformant; opens without repair. issues: {:?}",
        report.issues
    );
}

#[test]
fn del_instrtext_outside_complex_field_is_deleted_regular_text() {
    let body = r#"<w:p><w:r><w:t xml:space="preserve">Before </w:t></w:r><w:del w:id="5" w:author="A" w:date="2026-01-01T00:00:00Z"><w:r><w:delInstrText>GONE</w:delInstrText></w:r></w:del><w:r><w:t xml:space="preserve"> after</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_eq!(
        accept_text(&b),
        "Before  after",
        "ISO 29500-1 §17.16.13 — a non-field delInstrText is regular deleted text; accepting \
         removes 'GONE', leaving 'Before ' + ' after'."
    );
    assert_eq!(
        reject_text(&b),
        "Before GONE after",
        "ISO 29500-1 §17.16.13 — rejecting the deletion restores the regular text 'GONE' (not \
         field-code machinery to be hidden), so the reading is 'Before GONE after'."
    );
    let report = opens_clean(&b);
    assert!(
        report.ok,
        "ISO 29500-1 §17.16.13 — a delInstrText within a w:del is conformant; opens without \
         repair. issues: {:?}",
        report.issues
    );
}

#[test]
fn complex_field_result_region_text_is_displayed() {
    let body = r#"<w:p><w:r><w:fldChar w:fldCharType="begin"/></w:r><w:r><w:instrText>AUTHOR</w:instrText></w:r><w:r><w:fldChar w:fldCharType="separate"/></w:r><w:r><w:t>Rex Jaeschke</w:t></w:r><w:r><w:fldChar w:fldCharType="end"/></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let report = opens_clean(&b);
    assert!(
        report.ok,
        "ISO 29500-1 §17.16.2 — a balanced begin/separate/end complex field is conformant; \
         opens without repair. issues: {:?}",
        report.issues
    );
    assert_eq!(
        accept_text(&b),
        "Rex Jaeschke",
        "ISO 29500-1 §17.16.2 / §17.16.18 — the result region (separate..end) is the displayed \
         field result; the field code AUTHOR is hidden. Untracked => accept reads the result."
    );
    assert_eq!(
        reject_text(&b),
        "Rex Jaeschke",
        "ISO 29500-1 §17.16.2 / §17.16.18 — untracked, so reject reads the same cached result; \
         the field code AUTHOR is never displayed."
    );
}

#[ignore = "open question: §17.16.18 — field with begin/codes/end and NO separate has no result region; everything between begin and end is field code and must not display, but stemma surfaces the <w:t>HELLO</w:t> run between begin and end, leaking field-code content into the read text"]
#[test]
fn complex_field_no_separate_result_runs_are_field_codes() {
    let body = r#"<w:p><w:r><w:t xml:space="preserve">before </w:t></w:r><w:r><w:fldChar w:fldCharType="begin"/></w:r><w:r><w:instrText>PAGE</w:instrText></w:r><w:r><w:t>HELLO</w:t></w:r><w:r><w:fldChar w:fldCharType="end"/></w:r><w:r><w:t xml:space="preserve"> after</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let report = opens_clean(&b);
    assert!(
        report.ok,
        "ISO 29500-1 §17.16.18 — a begin/codes/end field with no separate is a valid \
         result-less complex field; opens without repair. issues: {:?}",
        report.issues
    );
    assert_eq!(
        accept_text(&b),
        "before  after",
        "ISO 29500-1 §17.16.18 — with no separate, the HELLO run is field code (not result) \
         and is not displayed; only the surrounding literals read. Untracked => accept==reject."
    );
}

