#[test]
fn nested_field_type_name_composition_roundtrips_structure() {
    let body = r#"<w:p><w:r><w:fldChar w:fldCharType="begin"/></w:r><w:r><w:instrText xml:space="preserve">DA</w:instrText></w:r><w:r><w:fldChar w:fldCharType="begin"/></w:r><w:r><w:instrText xml:space="preserve"> QUOTE "TE" </w:instrText></w:r><w:r><w:fldChar w:fldCharType="separate"/></w:r><w:r><w:t>TE</w:t></w:r><w:r><w:fldChar w:fldCharType="end"/></w:r><w:r><w:fldChar w:fldCharType="separate"/></w:r><w:r><w:t>x</w:t></w:r><w:r><w:fldChar w:fldCharType="end"/></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let report = opens_clean(&b);
    assert!(
        report.ok,
        "MS-OI29500 §2.1.454 — nested-field-type-name is a Word semantic restriction, not a \
         packaging-validity error; the well-formed run sequence opens clean. issues: {:?}",
        report.issues
    );
    let xml = reserialize(&b);
    assert!(
        contains_in_order(
            &xml,
            &[
                "fldCharType=\"begin\"",
                "fldCharType=\"begin\"",
                "fldCharType=\"separate\"",
                "fldCharType=\"end\"",
                "fldCharType=\"separate\"",
                "fldCharType=\"end\"",
            ],
        ),
        "ISO 29500-1 §17.16.2 — both begins precede the inner separate/end and the outer \
         separate/end follow the inner end; the serializer must not flatten the inner field \
         because the outer type token is malformed. xml=\n{xml}"
    );
    assert!(
        xml.contains("QUOTE \"TE\""),
        "ISO 29500-1 §17.16.2 — the inner field instruction must survive verbatim; the engine \
         must not strip/rewrite the inner field when the outer type-name is non-resolvable. \
         xml=\n{xml}"
    );
}

#[test]
fn orphan_separate_fldchar_no_begin_reads_literal() {
    let body = r#"<w:p><w:r><w:t xml:space="preserve">A</w:t></w:r><w:r><w:fldChar w:fldCharType="separate"/></w:r><w:r><w:t>B</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_eq!(
        accept_text(&b),
        "AB",
        "ISO 29500-1 §17.16.18 — with no begin (no valid field), runs are processed as if the \
         field characters did not exist; only literal A and B read."
    );
    assert_eq!(
        reject_text(&b),
        "AB",
        "ISO 29500-1 §17.16.18 — untracked content reads identically under reject; the lone \
         separate contributes no displayed text."
    );
    let report = opens_clean(&b);
    assert!(
        report.ok,
        "ISO 29500-1 §17.18.29 — separate is a valid ST_FldCharType, so an unpaired separate is \
         schema-valid and opens without repair. issues: {:?}",
        report.issues
    );
}

