#[test]
fn begin_separate_end_field_with_empty_field_code() {
    let body = r#"<w:p><w:r><w:fldChar w:fldCharType="begin"/></w:r><w:r><w:fldChar w:fldCharType="separate"/></w:r><w:r><w:t>cached</w:t></w:r><w:r><w:fldChar w:fldCharType="end"/></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let xml = reserialize(&b);
    assert!(
        contains_in_order(
            &xml,
            &[
                "fldCharType=\"begin\"",
                "fldCharType=\"separate\"",
                "fldCharType=\"end\"",
            ],
        ),
        "ISO 29500-1 §17.16.2 — boundary fldChars must serialize in begin->separate->end order \
         even with no field code; the serializer must not reorder the pair. xml=\n{xml}"
    );
    assert!(
        !xml.contains("<w:instrText"),
        "ISO 29500-1 §17.16.2 — instrText is the field-code element; the serializer must not \
         synthesize one for an empty-code field (no fabrication of an instruction). xml=\n{xml}"
    );
    assert_eq!(
        accept_text(&b),
        "cached",
        "ISO 29500-1 §17.16.2 — the separate..end region is the cached result and is displayed \
         even when the field code is empty."
    );
    let report = opens_clean(&b);
    assert!(
        report.ok,
        "ISO 29500-1 §17.16.2 — a balanced begin/separate/end field with no field code is \
         schema-valid; opens without repair. issues: {:?}",
        report.issues
    );
}

