#[test]
fn complex_field_begin_carries_flddata_child_preserved_and_opens_clean() {
    let body = r#"<w:p><w:r><w:fldChar w:fldCharType="begin"><w:fldData xml:space="preserve">AQIDBA==</w:fldData></w:fldChar></w:r><w:r><w:instrText xml:space="preserve"> ADDIN TEST </w:instrText></w:r><w:r><w:fldChar w:fldCharType="separate"/></w:r><w:r><w:t>cached</w:t></w:r><w:r><w:fldChar w:fldCharType="end"/></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let report = opens_clean(&b);
    assert!(
        report.ok,
        "ISO 29500-1 §17.16.18 / §A.1 (CT_FldChar) — CT_FldChar's content model allows a fldData \
         child (CT_Text); a begin fldChar carrying fldData is schema-valid and opens without \
         repair. issues: {:?}",
        report.issues
    );
    let xml = reserialize(&b);
    // fldData must re-emit as a child of the SAME fldChar element with base64 intact.
    assert!(
        contains_in_order(
            &xml,
            &[
                "<w:fldChar",
                "<w:fldData",
                "AQIDBA==",
                "</w:fldData>",
                "</w:fldChar>",
            ],
        ),
        "ISO 29500-1 §A.1 — fldData is a child of the fldChar element (CT_FldChar choice); the \
         serializer must re-emit it nested inside the same fldChar with content intact, not as a \
         sibling run. xml=\n{xml}"
    );
}
